199	/// makes the gate robust to future re-use.
200	///
201	/// TODO(slice 2.6+): widen `Priv::trap_mask` from `u16` to `u32` to
202	/// match MINIX 3's `unsigned int` so SENDA's bit (16) actually fits.
203	/// Until then SENDA is dispatcher-denied here even though
204	/// `mini_senda` would otherwise reply `ENOSYS` — see the note on
205	/// `senda::mini_senda`.
206	#[inline]
207	fn trap_gate(trap_mask: u16, call_nr: i32, f: impl FnOnce() -> i32) -> i32 {
208	    let bit = 1u32.wrapping_shl(call_nr as u32);
209	    if (trap_mask as u32) & bit == 0 {
210	        return ETRAPDENIED;
211	    }
212	    f()
213	}
