215	/// `SENDREC` is the atomic-send-then-receive primitive used by every
216	/// `_syscall()` wrapper. SEND half blocks (or delivers); on success we
217	/// mark `MF_REPLY_PEND` and run the RECEIVE half against the same partner.
218	fn do_sendrec(
219	    proc_table: &mut [Proc; N_PROC_SLOTS],
220	    priv_table: &mut [Priv; NR_SYS_PROCS],
221	    caller_nr: ProcNr,
222	    dst_e: Endpoint,
223	    user_msg_va: u64,
224	) -> i32 {
225	    let send_result = send::mini_send(
226	        proc_table,
227	        priv_table,
228	        caller_nr,
229	        dst_e,
230	        user_msg_va,
231	        SendFlags::Blocking,
232	    );
233	    if send_result != OK {
234	        return send_result;
235	    }
236	    let Some(caller_idx) = proc_index(caller_nr) else {
237	        return EBADCALL;
238	    };
239	    proc_table[caller_idx].misc_flags |= MF_REPLY_PEND;
240	    receive::mini_receive(
241	        proc_table,
242	        priv_table,
243	        caller_nr,
244	        dst_e,
245	        user_msg_va,
246	        RecvFlags::Blocking,
247	    )
248	}
