250	/// Copy a pending IPC message out to the user buffer recorded at
251	/// RECEIVE-time and clear `MF_DELIVERMSG`. Called from
252	/// `sched::schedule_next` on every EL1 → EL0 transition.
253	pub fn flush_deliver_msg(p: &mut Proc) {
254	    if p.misc_flags & MF_DELIVERMSG == 0 {
255	        return;
256	    }
257	    // Best-effort; if the user buffer is bad, slice 2.5 has no place to
258	    // signal that (the receiver hasn't returned yet). Phase 3 adds
259	    // MF_MSGFAILED + signal delivery to handle this. The bounds check
260	    // in `copy_msg_to_user` keeps an out-of-range VA from faulting EL1.
261	    let _ = message::copy_msg_to_user(p.deliver_msg_vir, &p.deliver_msg);
262	    p.misc_flags &= !MF_DELIVERMSG;
263	}
264	
265	/// SVC-tail shim. `trap.S` calls this between `do_ipc` and
266	/// `el1_return_to_user`; it picks the next runnable proc (which may be
267	/// the same caller, may be a higher-priority receiver that just
268	/// unblocked, or may be someone else entirely if the caller blocked)
269	/// and flushes any pending message into the new current proc's user
270	/// buffer.
271	#[unsafe(no_mangle)]
272	pub extern "C" fn el1_svc_tail() {
273	    // SAFETY: SVC dispatch context — single-threaded, DAIF.I masked,
274	    // no other PROC_TABLE/RUNQ references live at this point.
275	    unsafe { sched::schedule_next() }
276	}
277	
