1	//! Slice-2.5 userland bootstrap: minimal TTBR0 setup + two EL0 stub tasks
2	//! that exchange IPC messages.
3	//!
4	//! Builds a 4-level page-table walk in static `.bss` storage that maps
5	//! five user pages: one code page per stub plus one stack page per stub.
6	//!   - `USER_CODE_VA_A` → physical `USER_CODE_PAGE_A` filled with the
7	//!     sender stub (`_user_stub_a_start..._user_stub_a_end`). RO + EL0 X.
8	//!   - `USER_CODE_VA_B` → physical `USER_CODE_PAGE_B` filled with the echo
9	//!     stub (`_user_stub_b_start..._user_stub_b_end`). RO + EL0 X.
10	//!   - `USER_STACK_VA_A` / `USER_STACK_VA_B` → two kernel-owned pages used
11	//!     as each stub's EL0 stack. RW + EL0, no execute.
12	//!
13	//! Each stub also gets its own privilege-table slot (16 = A, 17 = B) with
14	//! `trap_mask = SRV_T` and `ipc_to` cross-linking A↔B — that's what lets
15	//! the slice-2.5 IPC trap-mask and `ipc_to` enforcement permit the
16	//! ping-pong while denying any other endpoint.
17	//!
18	//! After populating each stub's process slot and priv slot, the bootstrap
19	//! enqueues both into the priority-banded run queue. The caller
20	//! (`kmain`) then transfers control to the scheduler via `proc::sched::run`.
21	//!
22	//! Phase 3's VM server replaces this entire file with proper per-process
23	//! address spaces, ELF loading, and copy-on-write semantics.
24	
25	use core::cell::UnsafeCell;
26	use core::sync::atomic::Ordering;
27	
28	use minix4_kernel_shared::{PrivId, ProcNr};
29	use minix4_kernel_shared::com::{RS_PROC_NR, boot_endpoint};
30	
31	use crate::arch::aarch64::limine::kernel_va_to_pa;
32	use crate::arch::aarch64::mmu::{
33	    self, ATTR_IDX_NORMAL, PAGE_SIZE, PTE_AF, PTE_AP_RO_EL0, PTE_AP_RW_EL0, PTE_PXN,
34	    PTE_SH_INNER, PTE_UXN, PageTable, pte_attr_idx,
35	};
36	use crate::proc::flags::{BILLABLE, PREEMPTIBLE, SRV_T, SYS_PROC};
37	use crate::proc::sched;
38	use crate::proc::table::{priv_slot_mut, proc_slot_mut};
39	use crate::proc::{Priv, Proc};
40	
41	// ----- EL0 virtual addresses ------------------------------------------------
42	
43	/// VA at which stub A's code page is mapped.
44	pub const USER_CODE_VA_A: u64 = 0x0040_0000; // 4 MiB
45	/// VA at which stub A's stack page is mapped.
46	pub const USER_STACK_VA_A: u64 = 0x0080_0000; // 8 MiB
47	
48	/// VA at which stub B's code page is mapped (one 4 KiB page above A).
49	/// Same 2 MiB L2 slot as A, so the L3_CODE table is shared.
50	pub const USER_CODE_VA_B: u64 = 0x0041_0000;
51	/// VA at which stub B's stack page is mapped. Same 2 MiB L2 slot as A's
52	/// stack, so the L3_STACK table is shared.
53	pub const USER_STACK_VA_B: u64 = 0x0081_0000;
54	
55	/// First proc-table slot beyond the boot image — `ProcNr(11)`. Boot procs
56	/// occupy `0..=INIT_PROC_NR` (i.e. `0..=10`).
57	const STUB_A_PROC_NR: ProcNr = ProcNr::new(11);
58	/// Second stub slot, just after A.
59	const STUB_B_PROC_NR: ProcNr = ProcNr::new(12);
60	
61	/// Privilege-table slots for the two stubs. Boot image uses 0..=15;
62	/// 16 and 17 are the first free entries.
63	const STUB_A_PRIV_ID: PrivId = PrivId::new(16);
64	const STUB_B_PRIV_ID: PrivId = PrivId::new(17);
65	
66	// SPSR_EL1 to install on each stub's `eret`. Compared to slice 2.3's
67	// `0x3C0` (all four DAIF bits masked), we clear bit 7 (`I`) so that IRQs
68	// are unmasked at EL0 — that's the whole point of slice 2.4. Bits set:
69	//   - bit 9 (D) = 1     // debug mask
70	//   - bit 8 (A) = 1     // SError mask
71	//   - bit 7 (I) = 0     // IRQs ENABLED at EL0
72	//   - bit 6 (F) = 1     // FIQ mask (we don't handle FIQ in slice 2.4)
73	//   - bits 3:0 (M)     = 0 // EL0t
74	const STUB_SPSR_EL0: u64 = 0x340;
75	
76	// ----- Static storage ------------------------------------------------------
77	
78	/// 4 KiB-aligned raw byte page, used for the EL0 stubs' code and stacks.
79	#[repr(C, align(4096))]
80	struct UserPage(UnsafeCell<[u8; PAGE_SIZE]>);
81	// SAFETY: single-threaded boot context; no concurrent access. Same invariant
82	// documented on `ProcStorage` / `PrivStorage` in `proc::table`.
83	unsafe impl Sync for UserPage {}
84	
85	impl UserPage {
86	    const EMPTY: Self = Self(UnsafeCell::new([0; PAGE_SIZE]));
87	}
88	
89	#[repr(transparent)]
90	struct PtSlot(UnsafeCell<PageTable>);
91	// SAFETY: single-threaded boot; mutation is confined to `userland_bootstrap`.
92	unsafe impl Sync for PtSlot {}
93	
94	static L0_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
95	static L1_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
96	static L2_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
97	static L3_CODE_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
98	static L3_STACK_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
99	
100	/// Per-task code pages — A is the sender stub, B is the echo stub.
101	static USER_CODE_PAGE_A: UserPage = UserPage::EMPTY;
102	static USER_CODE_PAGE_B: UserPage = UserPage::EMPTY;
103	/// Per-task stack pages.
104	static USER_STACK_PAGE_A: UserPage = UserPage::EMPTY;
105	static USER_STACK_PAGE_B: UserPage = UserPage::EMPTY;
106	
107	// ----- EL0 stub blobs (linked into the kernel image by `user_stub.S`) ------
108	
109	unsafe extern "C" {
110	    static _user_stub_a_start: u8;
111	    static _user_stub_a_end: u8;
112	    static _user_stub_b_start: u8;
113	    static _user_stub_b_end: u8;
114	}
115	
116	// ----- Bootstrap ----------------------------------------------------------
117	
118	/// Wire up TTBR0 mappings, copy the EL0 stub into its shared code page,
119	/// populate both stub proc slots, and enqueue them on the run queue.
120	///
121	/// SAFETY: must be called exactly once from `kmain` before any EL0 code
122	/// runs. Single-threaded boot context; no other reference into the static
123	/// page-table arena, user pages, or `PROC_TABLE[STUB_*_PROC_NR]` may exist
124	/// concurrently.
125	pub unsafe fn userland_bootstrap() {
126	    // 1. Verify Limine left MAIR_EL1's index 0 as Normal WB and that
127	    //    TCR_EL1's TTBR0-side fields match what `activate_user_ttbr0`
128	    //    expects.
129	    mmu::assert_mair_normal_wb();
130	    mmu::assert_tcr_el1_ttbr0_ready();
131	
132	    // 2. Resolve physical addresses for our static storage.
133	    let l0_pa = kernel_pa_of(L0_TABLE.0.get() as u64);
134	    let l1_pa = kernel_pa_of(L1_TABLE.0.get() as u64);
135	    let l2_pa = kernel_pa_of(L2_TABLE.0.get() as u64);
136	    let l3_code_pa = kernel_pa_of(L3_CODE_TABLE.0.get() as u64);
137	    let l3_stack_pa = kernel_pa_of(L3_STACK_TABLE.0.get() as u64);
138	    let code_a_pa = kernel_pa_of(USER_CODE_PAGE_A.0.get() as u64);
139	    let code_b_pa = kernel_pa_of(USER_CODE_PAGE_B.0.get() as u64);
140	    let stack_a_pa = kernel_pa_of(USER_STACK_PAGE_A.0.get() as u64);
141	    let stack_b_pa = kernel_pa_of(USER_STACK_PAGE_B.0.get() as u64);
142	
143	    // 3. Build the user mappings. Each stub now has its own physical
144	    //    code page so A (sender) and B (echo) can run distinct programs.
145	    //    The four VAs split into two L2 slots (one for the 0x40_xxxx code
146	    //    pair, one for the 0x80_xxxx stack pair), each backed by a single
147	    //    L3 table.
148	    let code_attrs =
149	        PTE_AF | PTE_SH_INNER | PTE_AP_RO_EL0 | PTE_PXN | pte_attr_idx(ATTR_IDX_NORMAL);
150	    let stack_attrs = PTE_AF
151	        | PTE_SH_INNER
152	        | PTE_AP_RW_EL0
153	        | PTE_PXN
154	        | PTE_UXN
155	        | pte_attr_idx(ATTR_IDX_NORMAL);
156	
157	    // SAFETY: single-threaded boot; no other references into the table
158	    // storage exist. PAs were resolved above.
159	    unsafe {
160	        let l0 = &mut *L0_TABLE.0.get();
161	        let l1 = &mut *L1_TABLE.0.get();
162	        let l2 = &mut *L2_TABLE.0.get();
163	        let l3_code = &mut *L3_CODE_TABLE.0.get();
164	        let l3_stack = &mut *L3_STACK_TABLE.0.get();
165	
166	        mmu::map_4k(
167	            l0, l1, l2, l3_code,
168	            l1_pa, l2_pa, l3_code_pa,
169	            USER_CODE_VA_A, code_a_pa, code_attrs,
170	        );
171	        mmu::map_4k(
172	            l0, l1, l2, l3_code,
173	            l1_pa, l2_pa, l3_code_pa,
174	            USER_CODE_VA_B, code_b_pa, code_attrs,
175	        );
176	        mmu::map_4k(
177	            l0, l1, l2, l3_stack,
178	            l1_pa, l2_pa, l3_stack_pa,
179	            USER_STACK_VA_A, stack_a_pa, stack_attrs,
180	        );
181	        mmu::map_4k(
182	            l0, l1, l2, l3_stack,
183	            l1_pa, l2_pa, l3_stack_pa,
184	            USER_STACK_VA_B, stack_b_pa, stack_attrs,
185	        );
186	    }
187	
188	    // 4. Copy each EL0 stub into its own code page; clean+invalidate so
189	    //    the upcoming EL0 fetches see the new bytes.
190	    // SAFETY: `_user_stub_*_start/end` are rodata symbols inside the
191	    // kernel image; start ≤ end is enforced by the linker.
192	    unsafe {
193	        copy_stub_into_page(
194	            &USER_CODE_PAGE_A,
195	            &_user_stub_a_start,
196	            &_user_stub_a_end,
197	        );
198	        copy_stub_into_page(
199	            &USER_CODE_PAGE_B,
200	            &_user_stub_b_start,
201	            &_user_stub_b_end,
202	        );
203	    }
204	
205	    // 5. Install TTBR0 with our L0 root.
206	    // SAFETY: DAIF is still masked from boot.
207	    unsafe { mmu::activate_user_ttbr0(l0_pa) };
208	
209	    // 6. Populate each stub's proc slot. Borrows are sequential, never
210	    //    overlapping.
211	    // SAFETY: single-threaded boot; sequential mutable borrows.
212	    unsafe {
213	        let pa = proc_slot_mut(STUB_A_PROC_NR).expect("STUB_A_PROC_NR within table");
214	        populate_stub_slot(
215	            pa,
216	            STUB_A_PROC_NR,
217	            STUB_A_PRIV_ID,
218	            b'A',
219	            USER_CODE_VA_A,
220	            USER_STACK_VA_A + PAGE_SIZE as u64,
221	        );
222	    }
223	    // SAFETY: same — A's borrow has been dropped before we take B.
224	    unsafe {
225	        let pb = proc_slot_mut(STUB_B_PROC_NR).expect("STUB_B_PROC_NR within table");
226	        populate_stub_slot(
227	            pb,
228	            STUB_B_PROC_NR,
229	            STUB_B_PRIV_ID,
230	            b'B',
231	            USER_CODE_VA_B,
232	            USER_STACK_VA_B + PAGE_SIZE as u64,
233	        );
234	    }
235	
236	    // 7. Install priv slots for the two stubs (trap_mask + ipc_to bits
237	    //    that let A↔B and nothing else).
238	    // SAFETY: single-threaded boot; install_stub_privs only touches
239	    // priv-table slots 16 and 17 sequentially.
240	    unsafe { install_stub_privs() };
241	
242	    // 8. Enqueue both on the scheduler. They run in FIFO order within the
243	    //    same priority band (SRV_Q); the timer will preempt A after one
244	    //    quantum and B will get its first slice.
245	    // SAFETY: single-threaded boot; sched module's invariants documented
246	    // on `enqueue`. No other PROC_TABLE / RUNQ borrows live.
247	    unsafe {
248	        sched::enqueue(STUB_A_PROC_NR);
249	        sched::enqueue(STUB_B_PROC_NR);
250	    }
251	}
252	
253	/// Copy bytes from `[stub_start, stub_end)` into `page` and flush the
254	/// I-cache for the range so the upcoming EL0 fetch sees the new code.
255	///
256	/// SAFETY: `stub_start` / `stub_end` must be a valid contiguous range in
257	/// the kernel image; `page` must be a 4 KiB-aligned BSS page we hold
258	/// exclusively.
259	unsafe fn copy_stub_into_page(page: &UserPage, stub_start: *const u8, stub_end: *const u8) {
260	    // SAFETY: `stub_end - stub_start` is non-negative by linker layout.
261	    let len = unsafe { stub_end.offset_from(stub_start) } as usize;
262	    assert!(len > 0 && len <= PAGE_SIZE);
263	    // SAFETY: caller's invariants — page is a 4 KiB-aligned writable BSS
264	    // page and we hold the only mutable reference (single-threaded boot).
265	    unsafe {
266	        let dst = page.0.get() as *mut u8;
267	        core::ptr::copy_nonoverlapping(stub_start, dst, len);
268	        mmu::flush_icache_range(page.0.get() as u64, len);
269	    }
270	}
271	
272	/// Install priv slots for the two slice-2.5 stubs. Must run after
273	/// `proc::init` (so slots 0..=15 are populated) and before
274	/// `sched::enqueue` (so the IPC path sees the priv_id when the stubs
275	/// first SVC).
276	///
277	/// SAFETY: single-threaded boot; touches priv-table slots 16 and 17
278	/// sequentially.
279	unsafe fn install_stub_privs() {
280	    // SAFETY: sequential mutable borrow.
281	    unsafe {
282	        install_one_stub_priv(
283	            STUB_A_PRIV_ID,
284	            STUB_A_PROC_NR,
285	            STUB_B_PRIV_ID,
286	        );
287	    }
288	    // SAFETY: A's borrow has been dropped before we take B's slot.
289	    unsafe {
290	        install_one_stub_priv(
291	            STUB_B_PRIV_ID,
292	            STUB_B_PROC_NR,
293	            STUB_A_PRIV_ID,
294	        );
295	    }
296	}
297	
298	/// Set the per-stub priv slot. `peer_priv_id` is the only target the
299	/// stub is permitted to send/notify (encoded as a single bit in `ipc_to`).
300	///
301	/// SAFETY: single-threaded boot; mutates only the priv slot at `id`.
302	unsafe fn install_one_stub_priv(id: PrivId, owner: ProcNr, peer_priv_id: PrivId) {
303	    // SAFETY: priv index in-range; no overlapping reference held.
304	    let pr: &mut Priv = unsafe {
305	        priv_slot_mut(id).expect("stub priv slot in range")
306	    };
307	    pr.id = id;
308	    pr.proc_nr = Some(owner);
309	    pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
310	    pr.trap_mask = SRV_T;
311	    pr.ipc_to.fill(0);
312	    let peer = peer_priv_id.as_usize();
313	    pr.ipc_to[peer / 32] |= 1u32 << (peer % 32);
314	    pr.k_call_mask.fill(0);
315	    pr.notify_pending.fill(0);
316	    pr.asyn_pending.fill(0);
317	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
318	}
319	
320	fn populate_stub_slot(
321	    p: &mut Proc,
322	    nr: ProcNr,
323	    priv_id: PrivId,
324	    id: u8,
325	    entry_va: u64,
326	    stack_top: u64,
327	) {
328	    // Name: `id` followed by "stub\0..." padding. Lets the clock tick
329	    // handler print `name[0]` to identify which stub is running, while
330	    // `dump_tables` shows a recognizable per-stub string.
331	    p.name = [0; 16];
332	    p.name[0] = id;
333	    p.name[1] = b'-';
334	    p.name[2] = b's';
335	    p.name[3] = b't';
336	    p.name[4] = b'u';
337	    p.name[5] = b'b';
338	
339	    p.nr = nr;
340	    p.endpoint = boot_endpoint(nr);
341	    p.priv_id = Some(priv_id);
342	    p.priority = crate::proc::table::SRV_Q;
343	    // 5 ticks per quantum = 50 ms at 100 Hz. Short enough to see frequent
344	    // A/B switches in the boot demo, long enough that the do_ipc trace
345	    // (one line per 100 SVCs) still gets a few samples per burst.
346	    p.quantum_ms = 5;
347	    p.quantum_left = p.quantum_ms as u64;
348	
349	    // EL0 entry state.
350	    p.regs.elr_el1 = entry_va;
351	    p.regs.sp_el0 = stack_top;
352	    p.regs.spsr_el1 = STUB_SPSR_EL0;
353	
354	    // Run-queue link starts cleared — `sched::enqueue` will set it.
355	    p.next_ready = None;
356	
357	    // Mark runnable.
358	    p.rts_flags.store(0, Ordering::Relaxed);
359	}
360	
361	/// Translate a kernel-image VA to PA via Limine's kernel-address response.
362	fn kernel_pa_of(va: u64) -> u64 {
363	    kernel_va_to_pa(va).expect(
364	        "Limine did not populate the kernel-address response — bootloader too old?",
365	    )
366	}
