71	pub const MF_VIRT_TIMER: u32 = 0x0_0002;
72	pub const MF_PROF_TIMER: u32 = 0x0_0004;
73	pub const MF_KCALL_RESUME: u32 = 0x0_0008;
74	pub const MF_DELIVERMSG: u32 = 0x0_0040;
75	pub const MF_SIG_DELAY: u32 = 0x0_0080;
76	pub const MF_FPU_INITIALIZED: u32 = 0x0_1000;
77	pub const MF_SENDING_FROM_KERNEL: u32 = 0x0_2000;
78	pub const MF_CONTEXT_SET: u32 = 0x0_4000;
79	pub const MF_SENDA_VM_MISS: u32 = 0x2_0000;
80	pub const MF_STEP: u32 = 0x4_0000;
