99	pub const CHECK_IO_PORT: u16 = 0x020;
100	/// Privilege subsystem checks IRQ assignments against `Priv::irqs`.
101	pub const CHECK_IRQ: u16 = 0x040;
102	/// Privilege subsystem checks VM memory-range requests against `Priv::mem_ranges`.
103	pub const CHECK_MEM: u16 = 0x080;
104	/// Root system process (the reincarnation server, RS).
105	pub const ROOT_SYS_PROC: u16 = 0x100;
106	/// VM system process — gets the dedicated VM privilege role.
107	pub const VM_SYS_PROC: u16 = 0x200;
108	/// Restarted system process (set on respawn).
109	pub const RST_SYS_PROC: u16 = 0x800;
110	
111	// ---------------------------------------------------------------------------
112	// Trap masks (`Priv::trap_mask`). Bit `i` allows IPC primitive `i`.
113	// ---------------------------------------------------------------------------
114	
115	/// Kernel-task trap mask — no IPC traps allowed (HARDWARE, IDLE, ASYNCM).
116	pub const TSK_T: u16 = 0;
117	/// "Constrained" kernel-task trap mask — only `RECEIVE` allowed (CLOCK, SYSTEM).
118	pub const CSK_T: u16 = 1 << RECEIVE;
