1	//! Priority-banded round-robin scheduler.
2	//!
3	//! Slice 2.4 grows `proc::sched` from the slice-2.3 stub (one fixed
4	//! current-proc tracker) into a real run-queue scheduler. Layout mirrors
5	//! MINIX 3 `kernel/proc.c:1605` (`enqueue`), `:1726` (`dequeue`), and
6	//! `:1795` (`pick_proc`), with two simplifications:
7	//!
8	//! - Queue linkage is a [`ProcNr`] index (`Proc::next_ready`) rather than a
9	//!   raw `struct proc *` — the project-wide convention from `CLAUDE.md`.
10	//! - No per-CPU run queues. Slice 2.4 is single-CPU.
11	//!
12	//! Concurrency model: the kernel runs DAIF-masked, so neither EL1 code nor
13	//! the IRQ handler can be interrupted by *another* IRQ before it finishes.
14	//! The IRQ stub itself is the only async writer; it runs to completion
15	//! before returning to EL0. That gives us the same single-threaded invariant
16	//! as the rest of the boot path, so we use the same `UnsafeCell` + `Sync`
17	//! newtype pattern documented on `ProcStorage` / `PrivStorage`.
18	
19	use core::cell::UnsafeCell;
20	use core::sync::atomic::{AtomicI32, Ordering};
21	
22	use minix4_kernel_shared::ProcNr;
23	
24	use crate::arch::ArchRegisterFrame;
25	use crate::proc::Proc;
26	use crate::proc::flags::RTS_NO_QUANTUM;
27	use crate::proc::table::proc_slot_mut;
28	
29	/// Number of scheduling-priority bands. Matches the constants in
30	/// `proc::table` (`TASK_Q = 0`, `IDLE_Q = 15`).
31	pub const NR_SCHED_QUEUES: usize = 16;
32	
33	/// Currently-running process number. `i32::MIN` is the "no process running"
34	/// sentinel — chosen because it can never collide with a real `ProcNr`
35	/// (kernel tasks are `-5..=-1`, user processes are `0..NR_PROCS`).
36	pub static CURRENT_PROC_NR: AtomicI32 = AtomicI32::new(i32::MIN);
37	
38	const NO_PROC: i32 = i32::MIN;
39	
40	// ---------------------------------------------------------------------------
41	// Run-queue storage.
42	// ---------------------------------------------------------------------------
43	
44	struct RunQueues {
45	    head: [Option<ProcNr>; NR_SCHED_QUEUES],
46	    tail: [Option<ProcNr>; NR_SCHED_QUEUES],
47	}
48	
49	#[repr(transparent)]
50	struct RunQueueStorage(UnsafeCell<RunQueues>);
51	// SAFETY: single-CPU; the kernel runs DAIF-masked, so the only async writer
52	// is the IRQ stub, which runs to completion before returning to EL0. No
53	// concurrent access is possible.
54	unsafe impl Sync for RunQueueStorage {}
55	
56	static RUNQ: RunQueueStorage = RunQueueStorage(UnsafeCell::new(RunQueues {
57	    head: [None; NR_SCHED_QUEUES],
58	    tail: [None; NR_SCHED_QUEUES],
59	}));
60	
61	// ---------------------------------------------------------------------------
62	// Current-proc accessors.
63	// ---------------------------------------------------------------------------
64	
65	/// Borrow the currently-running process's slot.
66	///
67	/// SAFETY: caller must respect the single-threaded-boot invariant on
68	/// `PROC_TABLE`. The returned `&'static mut Proc` must not alias any other
69	/// reference into the table.
70	pub unsafe fn current_proc_mut() -> Option<&'static mut Proc> {
71	    let n = CURRENT_PROC_NR.load(Ordering::Relaxed);
72	    if n == NO_PROC {
73	        return None;
74	    }
75	    // SAFETY: forwarded — caller holds the no-aliasing invariant.
76	    unsafe { proc_slot_mut(ProcNr::new(n)) }
77	}
78	
79	// ---------------------------------------------------------------------------
80	// Run-queue operations.
81	// ---------------------------------------------------------------------------
82	
83	/// Append `nr` to the tail of its priority band's run queue.
84	///
85	/// Mirrors MINIX 3 `kernel/proc.c:1605` `enqueue`. Panics if the process is
86	/// already linked into a queue.
87	///
88	/// SAFETY: caller must hold the single-threaded-boot invariant; no other
89	/// mutable reference into `PROC_TABLE` or `RUNQ` may be live.
90	pub unsafe fn enqueue(nr: ProcNr) {
91	    let prio = unsafe {
92	        let p = proc_slot_mut(nr).expect("enqueue: nr out of range");
93	        assert!(p.next_ready.is_none(), "enqueue: process already queued");
94	        p.priority as usize
95	    };
96	    assert!(prio < NR_SCHED_QUEUES, "enqueue: priority out of range");
97	
98	    // SAFETY: RUNQ is a distinct static from PROC_TABLE; the prior
99	    // proc_slot_mut borrow has been dropped.
100	    let runq = unsafe { &mut *RUNQ.0.get() };
101	    match runq.tail[prio].replace(nr) {
102	        None => {
103	            // Queue was empty — set head too.
104	            runq.head[prio] = Some(nr);
105	        }
106	        Some(prev_tail) => {
107	            // SAFETY: prev_tail was in the queue, so its slot is valid.
108	            let tail_p = unsafe {
109	                proc_slot_mut(prev_tail).expect("enqueue: prev tail out of range")
110	            };
111	            tail_p.next_ready = Some(nr);
112	        }
113	    }
114	}
115	
116	/// Splice `nr` out of its priority band's run queue. No-op if not queued.
117	///
118	/// Mirrors MINIX 3 `kernel/proc.c:1726` `dequeue`. Slice 2.4's queues are
119	/// tiny (at most two entries), so the linear walk is fine.
120	///
121	/// SAFETY: caller must hold the single-threaded-boot invariant; no other
122	/// mutable reference into `PROC_TABLE` or `RUNQ` may be live.
123	pub unsafe fn dequeue(nr: ProcNr) {
124	    let prio = unsafe {
125	        proc_slot_mut(nr).expect("dequeue: nr out of range").priority as usize
126	    };
127	    // SAFETY: RUNQ is a distinct static from PROC_TABLE.
128	    let runq = unsafe { &mut *RUNQ.0.get() };
129	
130	    let mut prev: Option<ProcNr> = None;
131	    let mut cur = runq.head[prio];
132	    while let Some(c) = cur {
133	        // SAFETY: c was on the queue, so its slot is valid; no other live
134	        // reference into c's slot exists here.
135	        let next_after_c = unsafe {
136	            proc_slot_mut(c).expect("dequeue: c out of range").next_ready
137	        };
138	        if c == nr {
139	            // Clear the dequeued node's link.
140	            // SAFETY: same — single live reference at a time.
141	            unsafe {
142	                proc_slot_mut(c).expect("dequeue: c out of range").next_ready = None;
143	            }
144	            match prev {
145	                None => runq.head[prio] = next_after_c,
146	                Some(pn) => {
147	                    // SAFETY: pn was traversed already and is in the queue.
148	                    unsafe {
149	                        proc_slot_mut(pn)
150	                            .expect("dequeue: prev out of range")
151	                            .next_ready = next_after_c;
152	                    }
153	                }
154	            }
155	            if runq.tail[prio] == Some(c) {
156	                runq.tail[prio] = prev;
157	            }
158	            return;
159	        }
160	        prev = Some(c);
161	        cur = next_after_c;
162	    }
163	    // Not found — leave the queue untouched.
164	}
165	
166	/// Set bits in `p.rts_flags`; if the process transitions from runnable
167	/// (all-clear) to blocked, splice it out of the run queue.
168	///
169	/// Mirrors MINIX 3 `kernel/proc.h:206` `RTS_SET` — the macro that pairs
170	/// every `rts_flags |= …` with the corresponding `dequeue` call.
171	///
172	/// Caller pattern: hold `&mut Proc` to the affected slot, call this, then
173	/// let NLL drop the borrow before any subsequent `proc_slot_mut` against
174	/// the same slot — `dequeue` re-borrows internally.
175	///
176	/// SAFETY: caller must hold the single-threaded-boot / IRQ-masked
177	/// invariant on `PROC_TABLE` and `RUNQ`. The borrow on `p` ends at this
178	/// function's last use of it (capturing `nr`); the subsequent `dequeue`
179	/// then re-enters cleanly.
180	pub unsafe fn rts_set(p: &mut Proc, flag: u32) {
181	    let was_runnable = p.rts_flags.load(Ordering::Relaxed) == 0;
182	    p.rts_flags.fetch_or(flag, Ordering::Relaxed);
183	    let nr = p.nr;
184	    if was_runnable {
185	        // SAFETY: caller's invariants; `p`'s borrow has been captured.
186	        unsafe { dequeue(nr) }
187	    }
188	}
189	
190	/// Clear bits in `p.rts_flags`; if the process transitions from blocked
191	/// to runnable (all bits cleared), splice it onto the tail of its
192	/// priority band's run queue.
193	///
194	/// Mirrors MINIX 3 `kernel/proc.h:216` `RTS_UNSET` — the converse pairing
195	/// to `RTS_SET`. Note that unblocking from RTS_SENDING while RTS_RECEIVING
196	/// is also set (mid-SENDREC) does *not* enqueue, because `prev & !flag`
197	/// is still non-zero.
198	///
199	/// SAFETY: caller must hold the same invariant as [`rts_set`].
200	pub unsafe fn rts_unset(p: &mut Proc, flag: u32) {
201	    let prev = p.rts_flags.fetch_and(!flag, Ordering::Relaxed);
202	    let nr = p.nr;
203	    let now_runnable = (prev & !flag) == 0;
204	    if now_runnable && prev != 0 {
205	        // SAFETY: caller's invariants; `p`'s borrow has been captured.
206	        unsafe { enqueue(nr) }
207	    }
208	}
209	
210	/// Return the head of the highest-priority non-empty run queue.
211	///
212	/// Mirrors MINIX 3 `kernel/proc.c:1795` `pick_proc`. Lower priority value =
213	/// higher priority, so we scan `0..NR_SCHED_QUEUES` and return the first
214	/// non-empty head.
215	pub fn pick_proc() -> Option<ProcNr> {
216	    // SAFETY: read-only snapshot under the single-threaded invariant.
217	    let runq = unsafe { &*RUNQ.0.get() };
218	    runq.head.iter().find_map(|&h| h)
219	}
220	
221	// ---------------------------------------------------------------------------
222	// Dispatch helpers.
223	// ---------------------------------------------------------------------------
224	
225	unsafe extern "C" {
226	    /// Restores `tpidr_el1`-pointed `ArchRegisterFrame` and erets into EL0.
227	    /// Defined in `kernel/src/arch/aarch64/trap.S`.
228	    fn el1_return_to_user() -> !;
229	}
230	
231	/// Park `&mut p.regs` in `TPIDR_EL1` so the SVC/IRQ entry paths and
232	/// `el1_return_to_user` can locate the current process's register frame.
233	///
234	/// SAFETY: `p` must be the slot whose number is currently parked in
235	/// `CURRENT_PROC_NR`. Caller must hold the single-threaded invariant.
236	unsafe fn set_tpidr_to(p: &mut Proc) {
237	    let regs_ptr: *mut ArchRegisterFrame = &mut p.regs;
238	    // SAFETY: TPIDR_EL1 is EL1-only and used only by our own SVC + IRQ stubs
239	    // and `el1_return_to_user`. No other code reads or writes it.
240	    unsafe {
241	        core::arch::asm!(
242	            "msr tpidr_el1, {0}",
243	            "isb",
244	            in(reg) regs_ptr,
245	            options(nomem, nostack, preserves_flags),
246	        );
247	    }
248	}
249	
250	/// Pick the highest-priority runnable process, park its register frame in
251	/// `TPIDR_EL1`, and flush any pending `MF_DELIVERMSG` into its user
252	/// buffer. Called at every EL1 → EL0 transition (SVC tail, IRQ tail,
253	/// first-dispatch from `run`).
254	///
255	/// Does *not* touch the run queue — `rts_set`/`rts_unset` keep blocked
256	/// procs off, and `reschedule` handles the quantum-rotation case
257	/// separately. If `pick_proc` finds nothing runnable, the previous
258	/// current stays current.
259	///
260	/// TODO(slice 2.6+): once IDLE is enqueued at boot, an empty run queue
261	/// becomes an invariant violation rather than the expected
262	/// "both-stubs-briefly-blocked" state we see in slice 2.5. At that
263	/// point, add `debug_assert!(pick_proc().is_some(), "run queue empty
264	/// — IDLE missing?")` so a regression that dequeues IDLE blows up
265	/// loudly. Today only stubs A/B are enqueued (see
266	/// `arch/aarch64/userland.rs::userland_bootstrap`), so the assert
267	/// would fire spuriously.
268	///
269	/// SAFETY: caller must hold the single-threaded / IRQ-masked invariant
270	/// and must not hold any other reference into `PROC_TABLE` while this
271	/// runs.
272	pub unsafe fn schedule_next() {
273	    let next_nr = match pick_proc() {
274	        Some(nr) => nr,
275	        None => return,
276	    };
277	    CURRENT_PROC_NR.store(next_nr.get(), Ordering::Relaxed);
278	    // SAFETY: next_nr came from the run queue; single-borrow.
279	    unsafe {
280	        let next = proc_slot_mut(next_nr).expect("schedule_next: next out of range");
281	        set_tpidr_to(next);
282	        crate::ipc::flush_deliver_msg(next);
283	    }
284	}
285	
286	/// First entry into EL0 from `kmain`.
287	///
288	/// Pre-condition: the desired-to-run procs have already been [`enqueue`]d.
289	/// Picks the highest-priority head, parks its frame in `TPIDR_EL1`,
290	/// flushes any pending `MF_DELIVERMSG`, and jumps to the assembly
291	/// restore-and-`eret` stub. Never returns.
292	///
293	/// SAFETY: at least one process must be enqueued (otherwise we stay on
294	/// boot context with no `TPIDR_EL1` set). Must be called with DAIF (I)
295	/// still masked at EL1; the per-proc SPSR carries the EL0 mask state
296	/// that takes effect on `eret`.
297	pub unsafe fn run() -> ! {
298	    // SAFETY: forwarded.
299	    unsafe { schedule_next() }
300	    // SAFETY: trap.S contract documented at `el1_return_to_user`.
301	    unsafe { el1_return_to_user() }
302	}
303	
304	/// Quantum-exhaust path: rotate the current proc to the tail of its
305	/// priority band (refilling its quantum), then pick the next runnable.
306	///
307	/// Called from `clock::tick` when the running proc's `quantum_left` hits
308	/// zero. The IRQ stub's trailing `bl el1_return_to_user` reads the
309	/// (possibly new) `TPIDR_EL1` and restores that frame, so the context
310	/// switch happens transparently.
311	///
312	/// SAFETY: caller holds the single-threaded invariant; called only from
313	/// IRQ context with no other PROC_TABLE / RUNQ borrows live.
314	pub unsafe fn reschedule() {
315	    let cur_raw = CURRENT_PROC_NR.load(Ordering::Relaxed);
316	    if cur_raw != NO_PROC {
317	        let cur_nr = ProcNr::new(cur_raw);
318	        // SAFETY: single-threaded; cur_nr came from CURRENT_PROC_NR.
319	        let cur_runnable_after_refill = unsafe {
320	            let cur = proc_slot_mut(cur_nr).expect("reschedule: current out of range");
321	            cur.quantum_left = cur.quantum_ms as u64;
322	            cur.rts_flags.fetch_and(!RTS_NO_QUANTUM, Ordering::Relaxed);
323	            cur.rts_flags.load(Ordering::Relaxed) == 0
324	        };
325	        // Only rotate runnable cur. If cur is also blocked on something
326	        // else (e.g. IPC), `rts_set` already dequeued it — leave it off.
327	        if cur_runnable_after_refill {
328	            // SAFETY: cur_nr borrow above has been dropped.
329	            unsafe {
330	                dequeue(cur_nr);
331	                enqueue(cur_nr);
332	            }
333	        }
334	    }
335	
336	    // SAFETY: same single-threaded invariant.
337	    unsafe { schedule_next() }
338	}
339

